export const range = val => [...Array(val).keys()];
export const chunkArray = (array, perChunk = 5) => {
  return array.reduce((acc, cur, index) => {
    const chunkIndex = Math.floor(index / perChunk);

    if (!acc[chunkIndex]) {
      acc[chunkIndex] = [];
    }

    acc[chunkIndex].push(cur);
    return acc;
  }, []);
};